def solve(grid: Array[Array[Long]], x: Long, y: Long, k: Long): Array[Array[Long]] = {
  val matrix = grid.map(row => row.clone())
  val submatrix = (x until x + k).map(i => matrix(i).slice(y.toInt, y.toInt + k.toInt)).toArray
  val reversedSubmatrix = submatrix.reverse
  for (i <- 0 until k) {
    for (j <- 0 until k) {
      matrix(x + i)(y + j) = reversedSubmatrix(i)(j)
    }
  }
  matrix
}
